Here's a decorator for DRF's `@api_view` that implements similar behavior to your `user_stats` decorator:

```python
from functools import wraps
from rest_framework.decorators import api_view as drf_api_view

def user_stats_api_view(methods=None):
    def decorator(view_func):
        @wraps(view_func)
        def wrapped_view(request, *args, **kwargs):
            # Skip log user_stats if is_impersonate
            if (
                hasattr(request, 'auth') 
                and request.auth 
                and hasattr(request.auth, 'scope')
                and "impersonate" in str(request.auth.scope)
            ):
                return view_func(request, *args, **kwargs)

            # Update user stats if authenticated
            if request.user and request.user.is_authenticated:
                request.user.update_from_request(request)

            return view_func(request, *args, **kwargs)

        # Apply DRF's api_view decorator
        if methods:
            wrapped_view = drf_api_view(methods)(wrapped_view)
        else:
            wrapped_view = drf_api_view(['GET'])(wrapped_view) # Default to GET if no methods specified

        return wrapped_view
    return decorator
```

You can use it like this:

```python
# For a single HTTP method
@user_stats_api_view(['GET'])
def my_api_view(request):
    return Response({"message": "Hello!"})

# For multiple HTTP methods
@user_stats_api_view(['GET', 'POST'])
def my_api_view(request):
    return Response({"message": "Hello!"})
```

